}, {"id": "cmrulouid00011eqdblk00003", "type": "text input", "options": {"labels": {"button": "Send", "placeholder": "Type your message..."}, "variableId": "cmrulouid00011eqdvar00001"}}], "graphCoordinates": {"x": 0, "y": 0}}, {"id": "grp_sb_prjf4fd1f28808f437", "title": "Projects Submenu", "blocks": [{"id": "blk_sub_prje74dceff075442", "type": "choice input", "items": [{"id": "itm_sp_1fb44f73b442047a79", "content": "\ud83d\udccd County Projects", "outgoingEdgeId": "edg_sp_12616878dabc843ce8"}, {"id": "itm_sp_2bdf9221c509e44eaa", "content": "\ud83c\udfe0 Infrastructure", "outgoingEdgeId": "edg_sp_2a4fa9b88ae92433eb"}, {"id": "itm_sp_31409fc63a73043d58", "content": "\ud83c\udf31 Agriculture", "outgoingEdgeId": "edg_sp_32ef39e15ecb345429"}, {"id": "itm_sp_4dc60c3e321dd4110b", "content": "\ud83d\udd0c Energy & Roads", "outgoingEdgeId": "edg_sp_4c0be6ae4d9734294a"}], "options": {"variableId": "var_top1ab5fa2a51ed47d8b5"}}], "graphCoordinates": {"x": 0, "y": 200}}, {"id": "grp_sb_eco734955b6f2a2456", "title": "Economy Submenu", "blocks": [{"id": "blk_sub_eco4b11143735554a", "type": "choice input", "items": [{"id": "itm_se_1829067124a7140c29", "content": "\ud83d\udcbc Hustler Support", "outgoingEdgeId": "edg_se_1849fb1aebfba44bba"}, {"id": "itm_se_2815340d322754226b", "content": "\ud83d\udcbb Youth & Digital", "outgoingEdgeId": "edg_se_20ab3babd389c45729"}, {"id": "itm_se_3c5483d42e5f04c92b", "content": "\ud83d\udcca BETA Policies", "outgoingEdgeId": "edg_se_3342a2a324198418b9"}], "options": {"variableId": "var_top1ab5fa2a51ed47d8b5"}}], "graphCoordinates": {"x": 0, "y": 400}}, {"id": "grp_ask9d5c99ed0bfd456683", "title": "Ask Question", "blocks": [{"id": "blk_ask_txt24d78aa07a9445", "type": "text", "content": {"richText": [{"id": "p_170e371f6c1e422dadeb223", "type": "p", "children": [{"text": "Go ahead, type your question and I''ll get you a verified answer. \ud83c\uddf0\ud83c\uddea"}]}]}}], "graphCoordinates": {"x": 0, "y": 600}}, {"id": "grp_355c2cb9962b489e8232", "title": "Onboarding & Greeting", "blocks": [{"id": "blk_982367c7599f4503a271", "type": "text", "content": {"richText": [{"id": "p_b60a1a9313344a7a9182", "type": "p", "children": [{"text": "Sawa, {{user_name}}! \ud83d\udc4d Je, ungependa kujua kuhusu nini?"}]}]}}, {"id": "blk_cc4b2351044b4fcbacdb", "type": "choice input", "items": [{"id": "itm_1f7244f66bfe4569a7e8", "content": "\ud83c\udfd7\ufe0f Miradi & Maendeleo", "outgoingEdgeId": "edg_3e60eb884b38442586b6"}, {"id": "itm_8978a105563744fe9e07", "content": "\ud83d\udcb0 Uchumi & Fursa", "outgoingEdgeId": "edg_f2480a134918450f8ff2"}, {"id": "itm_edc4a11ac9b44a9497a6", "content": "\ud83d\udcac Uliza Swali", "outgoingEdgeId": "edg_1afd492098fc40a9bc42"}], "options": {"variableId": "var_top1ab5fa2a51ed47d8b5"}}], "graphCoordinates": {"x": -50, "y": 0}}, {"id": "grp_201e27a25aba46159fd1", "title": "Onboarding & Greeting", "blocks": [{"id": "blk_1646fd4822f942559735", "type": "text", "content": {"richText": [{"id": "p_02bfce95b67f41ce9c46", "type": "p", "children": [{"text": "Fiti, {{user_name}}! \ud83d\udc4d Unadaiku jua mambo gani?"}]}]}}, {"id": "blk_a352ab40a6524e6cb435", "type": "choice input", "items": [{"id": "itm_cee82f0c392f42acbfcc", "content": "\ud83c\udfd7\ufe0f Ma-Project", "outgoingEdgeId": "edg_7700c4d4c9cb4f758be0"}, {"id": "itm_c6869bbe99a4483f9d7b", "content": "\ud83d\udcb0 Biz & Doh", "outgoingEdgeId": "edg_37d7861c245141f7923f"}, {"id": "itm_5ce1c627be8b4bc98ea6", "content": "\ud83d\udcac Uliza Swali", "outgoingEdgeId": "edg_8aa88ecb58fb4a5e8586"}], "options": {"variableId": "var_top1ab5fa2a51ed47d8b5"}}], "graphCoordinates": {"x": 300, "y": 0}}, {"id": "grp_gtextaf351b936ae148db", "title": "Greeting 1", "graphCoordinates": {"x": -400, "y": 0}, "blocks": [{"id": "blk_gtext01ad00a155754ca9", "type": "text", "content": {"richText": [{"id": "p_afb4e079c55045ecabb6b97", "type": "p", "children": [{"text": "Habari yako, {{display_name}}! \ud83d\udc4b\n\nIt''s me, William Ruto. I know you''re busy, and I respect that. So let me be quick.\n\nThis is your direct line to what my government is doing for you, real projects, real money, real facts. No spin, no noise.\n\nWhat would you like to know today?"}]}]}, "outgoingEdgeId": "edg_gtext28a1bed73fbe4b89"}]}, {"id": "grp_gtext6d81995c12af409c", "title": "Greeting 2", "graphCoordinates": {"x": -400, "y": 150}, "blocks": [{"id": "blk_gtextd3040997f8e741d9", "type": "text", "content": {"richText": [{"id": "p_5ac6768d94734645b625543", "type": "p", "children": [{"text": "Sasa, {{display_name}}! \ud83c\uddf0\ud83c\uddea\n\nYou know me, I came from nothing, a chicken seller from Sugoi. I understand what it means to hustle every day for your family.\n\nThat''s exactly why I built this, so you can ask me anything, and I''ll give you straight answers about what we''re building for Kenya.\n\nWhat''s on your mind?"}]}]}, "outgoingEdgeId": "edg_gtext4115b9f662aa4a53"}]}, {"id": "grp_gtextddba8f872d524825", "title": "Greeting 3", "graphCoordinates": {"x": -400, "y": 300}, "blocks": [{"id": "blk_gtextedb5bdd06b6f43cf", "type": "text", "content": {"richText": [{"id": "p_f731106b280447338c8591c", "type": "p", "children": [{"text": "Habari za leo! \ud83d\udc4b\n\nI''m here. Not my spokesperson. Not a press release. Me.\n\nI started this because I believe in you, {{display_name}}, and every Kenyan deserves direct, honest communication about what your government is doing.\n\nAsk me anything, projects, policies, or what''s happening in your area. Facts only."}]}]}, "outgoingEdgeId": "edg_gtext1158f6681d8a4d6a"}]}, {"id": "grp_gtext78938bd8344048b4", "title": "Greeting 4", "graphCoordinates": {"x": -400, "y": 450}, "blocks": [{"id": "blk_gtext3b367f8413314823", "type": "text", "content": {"richText": [{"id": "p_4d9c42642f6a4bdebc26dd3", "type": "p", "children": [{"text": "Karibu sana, {{display_name}}. \ud83d\ude4f\n\nEvery morning I wake up thinking about one thing, how do I make sure the mwananchi''s life is better than yesterday?\n\nThis is where that conversation happens. Whether you''re a farmer, a trader, a student, or just a curious Kenyan, you belong here.\n\nWhat can I help you with today?"}]}]}, "outgoingEdgeId": "edg_gtextc4235b8a14ef4f47"}]}, {"id": "grp_gtext09629a65c21d43d4", "title": "Greeting 5", "graphCoordinates": {"x": -400, "y": 600}, "blocks": [{"id": "blk_gtextef2448baa6fa42f1", "type": "text", "content": {"richText": [{"id": "p_9910f3a4f67943e0b311cc2", "type": "p", "children": [{"text": "Karibu, {{display_name}}! \ud83d\udc4b\n\nKenya''s story is being written right now, and you are part of it.\n\nWhether you''re a hustler in Gikomba, a farmer in Rift Valley, a student in Kisumu, or a mama running a small business, this government is working for you.\n\nLet me show you what''s being done. Ask me anything. \ud83c\uddf0\ud83c\uddea"}]}]}, "outgoingEdgeId": "edg_gtextd7a93e89f3244e33"}]}, {"id": "grp_routerc5adee3cde1a444", "title": "Greeting Router", "graphCoordinates": {"x": -800, "y": 0}, "blocks": [{"id": "blk_cond6e2b30caf54048ad9", "type": "Condition", "items": [{"id": "itm_cond208e135ec1aa451b9", "content": {"logicalOperator": "AND", "comparisons": [{"id": "comp2a628df12f1e402aac825", "variableId": "var_grt_idxedc14a8436954e", "comparisonOperator": "Equal to", "value": "1"}]}, "outgoingEdgeId": "edg_cond534ebcce76394650a"}, {"id": "itm_cond8ac47aca7c24436fa", "content": {"logicalOperator": "AND", "comparisons": [{"id": "compcb9c454fdeed4fd2a2a67", "variableId": "var_grt_idxedc14a8436954e", "comparisonOperator": "Equal to", "value": "2"}]}, "outgoingEdgeId": "edg_condbdaab4430cf64de68"}, {"id": "itm_condf672235bbec6454f8", "content": {"logicalOperator": "AND", "comparisons": [{"id": "comp585daa6fc4f84c97acbd2", "variableId": "var_grt_idxedc14a8436954e", "comparisonOperator": "Equal to", "value": "3"}]}, "outgoingEdgeId": "edg_cond5df59e66ea69432db"}, {"id": "itm_cond784ba850bb8749de8", "content": {"logicalOperator": "AND", "comparisons": [{"id": "comp7c69838d24a44cbd9da8f", "variableId": "var_grt_idxedc14a8436954e", "comparisonOperator": "Equal to", "value": "4"}]}, "outgoingEdgeId": "edg_cond5d84b4ec901f47c4b"}, {"id": "itm_cond1ba3c5434a9c4e728", "content": {"logicalOperator": "AND", "comparisons": [{"id": "comp327cc7d9a27341b8902a7", "variableId": "var_grt_idxedc14a8436954e", "comparisonOperator": "Equal to", "value": "5"}]}, "outgoingEdgeId": "edg_cond7051064dc18b4faab"}]}]}]'::jsonb, '[{"id": "cmrulouid00011eqdvar00001", "name": "InitialMessage", "isSessionVariable": true}, {"id": "cmrulouid00011eqdvar00002", "name": "Reply", "isSessionVariable": true}, {"id": "cmrulouid00011eqdvar00003", "name": "user_name", "isSessionVariable": true}, {"id": "cmrulouid00011eqdvar00004", "name": "latest_news", "isSessionVariable": true}, {"id": "var_grt4436502efe0b42e991", "name": "Greeting", "isSessionVariable": true}, {"id": "var_lng4e9855517f074ae6b5", "name": "Language", "isSessionVariable": true}, {"id": "var_top1ab5fa2a51ed47d8b5", "name": "Topic", "isSessionVariable": true}, {"id": "var_grt_idxedc14a8436954e", "name": "greeting_index", "isSessionVariable": true}, {"id": "var_disp_nm2ea172148c034f", "name": "display_name", "isSessionVariable": true}]'::jsonb, '[{"id": "cmrulouid00011eqdedge0002", "to": {"blockId": "cmrulouid00011eqdblk00001", "groupId": "cmrulouid00011eqdgrp00001"}, "from": {"blockId": "cmrulouid00011eqdblk00003"}}, {"id": "edg_start90877cf2cb6042ca", "to": {"groupId": "grp_routerc5adee3cde1a444"}, "from": {"eventId": "cfwf885l7o317dh00p7izllvm"}}, {"id": "edg_lg_en757ef26d09274e71", "to": {"blockId": "blk_ask_tpd42ba2216f46491", "groupId": "grp_onbd1285ca548a2d456f8"}, "from": {"itemId": "itm_lg_en5dede8340c784bd3", "blockId": "blk_ch_lg782acf978c5b42e7"}}, {"id": "edg_lg_swf2df2afc11c34201", "to": {"groupId": "grp_355c2cb9962b489e8232"}, "from": {"itemId": "itm_lg_sw5623d8e830b44ead", "blockId": "blk_ch_lg782acf978c5b42e7"}}, {"id": "edg_lg_sh3c5b942dae534e3f", "to": {"groupId": "grp_201e27a25aba46159fd1"}, "from": {"itemId": "it